const body = $input.first().json.body || {};
const rawText = (body.text || body.article || body.content || '').trim();
const source = body.source || 'webhook';
if (!rawText || rawText.length < 50) {
  throw new Error('Input too short. Provide at least 50 characters in "text", "article", or "content".');
}
return [{ json: { rawText, source } }];

const raw = $input.first().json.content?.[0]?.text || $input.first().json.body?.content?.[0]?.text || '';
const out = { twitter: '', linkedin: '', email: '', raw };
const twitterMatch = raw.match(/===TWITTER_THREAD===([\s\S]*?)(?===LINKEDIN_POST===|$)/i);
const linkedinMatch = raw.match(/===LINKEDIN_POST===([\s\S]*?)(?===EMAIL_SNIPPET===|$)/i);
const emailMatch = raw.match(/===EMAIL_SNIPPET===([\s\S]*)/i);
if (twitterMatch) out.twitter = twitterMatch[1].trim();
if (linkedinMatch) out.linkedin = linkedinMatch[1].trim();
if (emailMatch) out.email = emailMatch[1].trim();
return [{ json: out }];
